commit e8604fedea84eacfe3f19185ba8441666acd80c2
Author: Marek Szyprowski <m.szyprowski@samsung.com>

of: reserved_mem: rework fdt_init_reserved_mem_node()

This commit merges fdt_reserved_mem_save_node() into
fdt_init_reserved_mem_node() to perform reserved memory region
initialization in a single step instead of two.

> diff --git a/drivers/of/of_reserved_mem.c b/drivers/of/of_reserved_mem.c
> index 037e3d74dde1..4e3a8d0716de 100644
> --- a/drivers/of/of_reserved_mem.c
> +++ b/drivers/of/of_reserved_mem.c

[ ... ]

> @@ -619,21 +595,34 @@ static int __init __reserved_mem_init_node(struct reserved_mem *rmem,

[ ... ]

>  static void __init fdt_init_reserved_mem_node(unsigned long node, const char *uname,
>  					      phys_addr_t base, phys_addr_t size)
>  {
>  	int err = 0;
>  	bool nomap;
>  
> +	struct reserved_mem *rmem = &reserved_mem[reserved_mem_count];
> +
> +	if (reserved_mem_count == total_reserved_mem_cnt) {
> +		pr_err("not enough space for all defined regions.\n");
> +		return;
> +	}
> +
> +	rmem->name = uname;
> +	rmem->base = base;
> +	rmem->size = size;
> +
>  	nomap = of_get_flat_dt_prop(node, "no-map", NULL) != NULL;
>  
>  	err = __reserved_mem_init_node(rmem, node);
> @@ -643,6 +632,7 @@ static void __init fdt_init_reserved_mem_node(struct reserved_mem *rmem,
>  			memblock_clear_nomap(rmem->base, rmem->size);
>  		else
>  			memblock_phys_free(rmem->base, rmem->size);
> +		return;

The commit message describes this as a simple refactoring, but does this
actually change the behavior for how failed memory regions are handled?

In the previous implementation, fdt_reserved_mem_save_node() unconditionally
incremented reserved_mem_count and saved the region, even if the region's
initialization failed and the memory was freed.

With the addition of the early return here, it looks like failed regions are
no longer saved in the reserved_mem array because the reserved_mem_count
increment is skipped.

While this appears to fix a potential bug where drivers might look up a
freed region and use its base and size, should this semantic change be
explicitly documented in the commit message?

>  	} else {
>  		phys_addr_t end = rmem->base + rmem->size - 1;
>  		bool reusable =
> @@ -654,6 +644,8 @@ static void __init fdt_init_reserved_mem_node(struct reserved_mem *rmem,
>  			reusable ? "reusable" : "non-reusable",
>  			rmem->name ? rmem->name : "unknown");
>  	}
> +
> +	reserved_mem_count++;
>  }

