    "content": "{"content":"// SPDX-License-Identifier: GPL-2.0+\n/*\n * Contiguous Memory Allocator for DMA mapping framework\n * Copyright (c) 2010-2011 by Samsung Electronics.\n * Written by:\n *\tMarek Szyprowski <m.szyprowski@samsung.com>\n *\tMichal Nazarewicz <mina86@mina86.com>\n *\n * Contiguous Memory Allocator\n *\n *   The Contiguous Memory Allocator (CMA) makes it possible to\n *   allocate big contiguous chunks of memory after the system has\n *   booted.\n *\n * Why is it needed?\n *\n *   Various devices on embedded systems have no scatter-getter and/or\n *   IO map support and require contiguous blocks of memory to\n *   operate.  They include devices such as cameras, hardware video\n *   coders, etc.\n *\n *   Such devices often require big memory buffers (a full HD frame\n *   is, for instance, more than 2 mega pixels large, i.e. more than 6\n *   MB of memory), which makes mechanisms such as kmalloc() or\n *   alloc_page() ineffective.\n *\n *   At the same time, a solution where a big memory region is\n *   reserved for a device is suboptimal since often more memory is\n *   reserved then strictly required and, moreover, the memory is\n *   inaccessible to page system even if device drivers don't use it.\n *\n *   CMA tries to solve this issue by operating on memory regions\n *   where only movable pages can be allocated from.  This way, kernel\n *   can use the memory for pagecache and when device driver requests\n *   it, allocated pages can be migrated.\n */\n\n#define pr_fmt(fmt) \"cma: \" fmt\n\n#include <asm/page.h>\n\n#include <linux/memblock.h>\n#include <linux/err.h>\n#include <linux/sizes.h>\n#include <linux/dma-buf/heaps/cma.h>\n#include <linux/dma-map-ops.h>\n#include <linux/cma.h>\n#include <linux/nospec.h>\n\n#ifdef CONFIG_CMA_SIZE_MBYTES\n#define CMA_SIZE_MBYTES CONFIG_CMA_SIZE_MBYTES\n#else\n#define CMA_SIZE_MBYTES 0\n#endif\n\nstruct cma *dma_contiguous_default_area;\n\n/*\n * Default global CMA area size can be defined in kernel's .config.\n * This is useful mainly for distro maintainers to create a kernel\n * that works correctly for most supported systems.\n * The size can be set in bytes or as a percentage of the total memory\n * in the system.\n *\n * Users, who want to set the size of global CMA area for their system\n * should use cma= kernel parameter.\n */\n#define size_bytes ((phys_addr_t)CMA_SIZE_MBYTES * SZ_1M)\nstatic phys_addr_t  size_cmdline __initdata = -1;\nstatic phys_addr_t base_cmdline __initdata;\nstatic phys_addr_t limit_cmdline __initdata;\n\nstatic int __init early_cma(char *p)\n{\n\tif (!p) {\n\t\tpr_err(\"Config string not provided\\n\");\n\t\treturn -EINVAL;\n\t}\n\n\tsize_cmdline = memparse(p, &p);\n\tif (*p != '@')\n\t\treturn 0;\n\tbase_cmdline = memparse(p + 1, &p);\n\tif (*p != '-') {\n\t\tlimit_cmdline = base_cmdline + size_cmdline;\n\t\treturn 0;\n\t}\n\tlimit_cmdline = memparse(p + 1, &p);\n\n\treturn 0;\n}\nearly_param(\"cma\", early_cma);\n\n#ifdef CONFIG_DMA_NUMA_CMA\n\nstatic struct cma *dma_contiguous_numa_area[MAX_NUMNODES];\nstatic phys_addr_t numa_cma_size[MAX_NUMNODES] __initdata;\nstatic struct cma *dma_contiguous_pernuma_area[MAX_NUMNODES];\nstatic phys_addr_t pernuma_size_bytes __initdata;\n\nstatic int __init early_numa_cma(char *p)\n{\n\tint nid, count = 0;\n\tunsigned long tmp;\n\tchar *s = p;\n\n\twhile (*s) {\n\t\tif (sscanf(s, \"%lu%n\", &tmp, &count) != 1)\n\t\t\tbreak;\n\n\t\tif (s[count] == ':') {\n\t\t\tif (tmp >= MAX_NUMNODES)\n\t\t\t\tbreak;\n\t\t\tnid = array_index_nospec(tmp, MAX_NUMNODES);\n\n\t\t\ts += count + 1;\n\t\t\ttmp = memparse(s, &s);\n\t\t\tnuma_cma_size[nid] = tmp;\n\n\t\t\tif (*s == ',')\n\t\t\t\ts++;\n\t\t\telse\n\t\t\t\tbreak;\n\t\t} else\n\t\t\tbreak;\n\t}\n\n\treturn 0;\n}\nearly_param(\"numa_cma\", early_numa_cma);\n\nstatic int __init early_cma_pernuma(char *p)\n{\n\tpernuma_size_bytes = memparse(p, &p);\n\treturn 0;\n}\nearly_param(\"cma_pernuma\", early_cma_pernuma);\n#endif\n\n#ifdef CONFIG_CMA_SIZE_PERCENTAGE\n\nstatic phys_addr_t __init __maybe_unused cma_early_percent_memory(void)\n{\n\tunsigned long total_pages = PHYS_PFN(memblock_phys_mem_size());\n\n\treturn (total_pages * CONFIG_CMA_SIZE_PERCENTAGE / 100) << PAGE_SHIFT;\n}\n\n#else\n\nstatic inline __maybe_unused phys_addr_t cma_early_percent_memory(void)\n{\n\treturn 0;\n}\n\n#endif\n\n#ifdef CONFIG_DMA_NUMA_CMA\nstatic void __init dma_numa_cma_reserve(void)\n{\n\tint nid;\n\n\tfor_each_node(nid) {\n\t\tint ret;\n\t\tchar name[CMA_MAX_NAME];\n\t\tstruct cma **cma;\n\n\t\tif (!node_online(nid)) {\n\t\t\tif (pernuma_size_bytes || numa_cma_size[nid])\n\t\t\t\tpr_warn(\"invalid node %d specified\\n\", nid);\n\t\t\tcontinue;\n\t\t}\n\n\t\tif (pernuma_size_bytes) {\n\n\t\t\tcma = &dma_contiguous_pernuma_area[nid];\n\t\t\tsnprintf(name, sizeof(name), \"pernuma%d\", nid);\n\t\t\tret = cma_declare_contiguous_nid(0, pernuma_size_bytes, 0, 0,\n\t\t\t\t\t\t\t 0, false, name, cma, nid);\n\t\t\tif (ret)\n\t\t\t\tpr_warn(\"%s: reservation failed: err %d, node %d\", __func__,\n\t\t\t\t\tret, nid);\n\t\t}\n\n\t\tif (numa_cma_size[nid]) {\n\n\t\t\tcma = &dma_contiguous_numa_area[nid];\n\t\t\tsnprintf(name, sizeof(name), \"numa%d\", nid);\n\t\t\tret = cma_declare_contiguous_nid(0, numa_cma_size[nid], 0, 0, 0, false,\n\t\t\t\t\t\t\t name, cma, nid);\n\t\t\tif (ret)\n\t\t\t\tpr_warn(\"%s: reservation failed: err %d, node %d\", __func__,\n\t\t\t\t\tret, nid);\n\t\t}\n\t}\n}\n#else\nstatic inline void __init dma_numa_cma_reserve(void)\n{\n}\n#endif\n\n/**\n * dma_contiguous_reserve() - reserve area(s) for contiguous memory handling\n * @limit: End address of the reserved memory (optional, 0 for any).\n *\n * This function reserves memory from early allocator. It should be\n * called by arch specific code once the early allocator (memblock or bootmem)\n * has been activated and all other subsystems have already allocated/reserved\n * memory.\n */\nvoid __init dma_contiguous_reserve(phys_addr_t limit)\n{\n\tphys_addr_t selected_size = 0;\n\tphys_addr_t selected_base = 0;\n\tphys_addr_t selected_limit = limit;\n\tbool fixed = false;\n\n\tdma_numa_cma_reserve();\n\n\tpr_debug(\"%s(limit %08lx)\\n\", __func__, (unsigned long)limit);\n\n\tif (size_cmdline != -1) {\n\t\tselected_size = size_cmdline;\n\t\tselected_base = base_cmdline;\n\n\t\t/* Hornor the user setup dma address limit */\n\t\tselected_limit = limit_cmdline ?: limit;\n\n\t\tif (base_cmdline + size_cmdline == limit_cmdline)\n\t\t\tfixed = true;\n\t} else {\n#ifdef CONFIG_CMA_SIZE_SEL_MBYTES\n\t\tselected_size = size_bytes;\n#elif defined(CONFIG_CMA_SIZE_SEL_PERCENTAGE)\n\t\tselected_size = cma_early_percent_memory();\n#elif defined(CONFIG_CMA_SIZE_SEL_MIN)\n\t\tselected_size = min(size_bytes, cma_early_percent_memory());\n#elif defined(CONFIG_CMA_SIZE_SEL_MAX)\n\t\tselected_size = max(size_bytes, cma_early_percent_memory());\n#endif\n\t}\n\n\tif (selected_size && !dma_contiguous_default_area) {\n\t\tint ret;\n\n\t\tpr_debug(\"%s: reserving %ld MiB for global area\\n\", __func__,\n\t\t\t (unsigned long)selected_size / SZ_1M);\n\n\t\tret = dma_contiguous_reserve_area(selected_size, selected_base,\n\t\t\t\t\t\t  selected_limit,\n\t\t\t\t\t\t  &dma_contiguous_default_area,\n\t\t\t\t\t\t  fixed);\n\t\tif (ret)\n\t\t\treturn;\n\n\t\tret = dma_heap_cma_register_heap(dma_contiguous_default_area);\n\t\tif (ret)\n\t\t\tpr_warn(\"Couldn't register default CMA heap.\");\n\t}\n}\n\nvoid __weak\ndma_contiguous_early_fixup(phys_addr_t base, unsigned long size)\n{\n}\n\n/**\n * dma_contiguous_reserve_area() - reserve custom contiguous area\n * @size: Size of the reserved area (in bytes),\n * @base: Base address of the reserved area optional, use 0 for any\n * @limit: End address of the reserved memory (optional, 0 for any).\n * @res_cma: Pointer to store the created cma region.\n * @fixed: hint about where to place the reserved area\n *\n * This function reserves memory from early allocator. It should be\n * called by arch specific code once the early allocator (memblock or bootmem)\n * has been activated and all other subsystems have already allocated/reserved\n * memory. This function allows to create custom reserved areas for specific\n * devices.\n *\n * If @fixed is true, reserve contiguous area at exactly @base.  If false,\n * reserve in range from @base to @limit.\n */\nint __init dma_contiguous_reserve_area(phys_addr_t size, phys_addr_t base,\n\t\t\t\t       phys_addr_t limit, struct cma **res_cma,\n\t\t\t\t       bool fixed)\n{\n\tint ret;\n\n\tret = cma_declare_contiguous(base, size, limit, 0, 0, fixed,\n\t\t\t\t\t\"reserved\", res_cma);\n\tif (ret)\n\t\treturn ret;\n\n\t/* Architecture specific contiguous memory fixup. */\n\tdma_contiguous_early_fixup(cma_get_base(*res_cma),\n\t\t\t\tcma_get_size(*res_cma));\n\n\treturn 0;\n}\n\n/**\n * dma_alloc_from_contiguous() - allocate pages from contiguous area\n * @dev:   Pointer to device for which the allocation is performed.\n * @count: Requested number of pages.\n * @align: Requested alignment of pages (in PAGE_SIZE order).\n * @no_warn: Avoid printing message about failed allocation.\n *\n * This function allocates memory buffer for specified device. It uses\n * device specific contiguous memory area if available or the default\n * global one. Requires architecture specific dev_get_cma_area() helper\n * function.\n */\nstruct page *dma_alloc_from_contiguous(struct device *dev, size_t count,\n\t\t\t\t       unsigned int align, bool no_warn)\n{\n\tif (align > CONFIG_CMA_ALIGNMENT)\n\t\talign = CONFIG_CMA_ALIGNMENT;\n\n\treturn cma_alloc(dev_get_cma_area(dev), count, align, no_warn);\n}\n\n/**\n * dma_release_from_contiguous() - release allocated pages\n * @dev:   Pointer to device for which the pages were allocated.\n * @pages: Allocated pages.\n * @count: Number of allocated pages.\n *\n * This function releases memory allocated by dma_alloc_from_contiguous().\n * It returns false when provided pages do not belong to contiguous area and\n * true otherwise.\n */\nbool dma_release_from_contiguous(struct device *dev, struct page *pages,\n\t\t\t\t int count)\n{\n\treturn cma_release(dev_get_cma_area(dev), pages, count);\n}\n\nstatic struct page *cma_alloc_aligned(struct cma *cma, size_t size, gfp_t gfp)\n{\n\tunsigned int align = min(get_order(size), CONFIG_CMA_ALIGNMENT);\n\n\treturn cma_alloc(cma, size >> PAGE_SHIFT, align, gfp & __GFP_NOWARN);\n}\n\n/**\n * dma_alloc_contiguous() - allocate contiguous pages\n * @dev:   Pointer to device for which the allocation is performed.\n * @size:  Requested allocation size.\n * @gfp:   Allocation flags.\n *\n * tries to use device specific contiguous memory area if available, or it\n * tries to use per-numa cma, if the allocation fails, it will fallback to\n * try default global one.\n *\n * Note that it bypass one-page size of allocations from the per-numa and\n * global area as the addresses within one page are always contiguous, so\n * there is no need to waste CMA pages for that kind; it also helps reduce\n * fragmentations.\n */\nstruct page *dma_alloc_contiguous(struct device *dev, size_t size, gfp_t gfp)\n{\n#ifdef CONFIG_DMA_NUMA_CMA\n\tint nid = dev_to_node(dev);\n#endif\n\n\t/* CMA can be used only in the context which permits sleeping */\n\tif (!gfpflags_allow_blocking(gfp))\n\t\treturn NULL;\n\tif (dev->cma_area)\n\t\treturn cma_alloc_aligned(dev->cma_area, size, gfp);\n\tif (size <= PAGE_SIZE)\n\t\treturn NULL;\n\n#ifdef CONFIG_DMA_NUMA_CMA\n\tif (nid != NUMA_NO_NODE && !(gfp & (GFP_DMA | GFP_DMA32))) {\n\t\tstruct cma *cma = dma_contiguous_pernuma_area[nid];\n\t\tstruct page *page;\n\n\t\tif (cma) {\n\t\t\tpage = cma_alloc_aligned(cma, size, gfp);\n\t\t\tif (page)\n\t\t\t\treturn page;\n\t\t}\n\n\t\tcma = dma_contiguous_numa_area[nid];\n\t\tif (cma) {\n\t\t\tpage = cma_alloc_aligned(cma, size, gfp);\n\t\t\tif (page)\n\t\t\t\treturn page;\n\t\t}\n\t}\n#endif\n\tif (!dma_contiguous_default_area)\n\t\treturn NULL;\n\n\treturn cma_alloc_aligned(dma_contiguous_default_area